use std::process::Command;
use std::path::Path;

fn convert_file(filename: &str, format: &str) -> Result<String, Box<dyn std::error::Error>> {
    let input_path = Path::new(filename);
    
    if !input_path.exists() {
        return Err("Input file does not exist".into());
    }
    
    let output_filename = format!("{}.{}", 
        input_path.file_stem().unwrap().to_str().unwrap(), 
        format
    );
    
    let output_path = input_path.with_file_name(&output_filename);
    
    let output_str = output_path.to_str().unwrap();
    
    let output = Command::new("ffmpeg")
        .args(&["-i", filename, "-y", output_str])
        .output()?;
    
    if !output.status.success() {
        return Err(format!("Conversion failed: {}", String::from_utf8_lossy(&output.stderr)).into());
    }
    
    Ok(output_str.to_string())
}